module RefModule(
    input clk,
    input rst,
    input ena,
    input [15:0] data_in,
    output reg [15:0] data_out
);reg [15:0] obf_shift_reg;

    always @(posedge clk) begin
        if (rst) begin
            obf_shift_reg <= 16'b0;
        end else if (ena) begin
            obf_shift_reg <= {obf_shift_reg[14:0], data_in[0]};
        end
    end

    assign data_out = obf_shift_reg;

endmodule
